{ pkgs, ... }:
{
  home.packages = [ pkgs.tmuxinator ];

  programs.tmux = {
    enable = true;
    extraConfig = builtins.readFile ./tmux.conf;
    plugins = with pkgs.tmuxPlugins; [
      sensible
      yank
      tmux-fzf
      resurrect
      continuum
      tmux-sessionx
      tmux-thumbs
      open
      extrakto
    ];
  };
}

